class ContributionTracker:
    """Track community contributions to the training dataset."""
    
    def __init__(self, metadata_path=None):
        self.metadata_path = metadata_path or os.path.join(DATA_FOLDER, "contributions.json")
        self.contributions = self._load_contributions()
    
    def _load_contributions(self):
        if os.path.exists(self.metadata_path):
            with open(self.metadata_path, "r") as f:
                return json.load(f)
        return {"contributions": [], "stats": {"total_images": 0, "total_contributors": 0, "class_distribution": {}}}
    
    def _save_contributions(self):
        with open(self.metadata_path, "w") as f:
            json.dump(self.contributions, f, indent=2, default=str)
    
    def add_contribution(self, contributor_id, filenames, labels, source="upload"):
        contribution = {
            "id": str(uuid.uuid4()),
            "contributor_id": contributor_id,
            "timestamp": datetime.utcnow().isoformat(),
            "filenames": filenames,
            "labels": labels,
            "source": source,
            "num_samples": len(filenames),
            "validated": False
        }
        self.contributions["contributions"].append(contribution)
        self.contributions["stats"]["total_images"] += len(filenames)
        
        # Update class distribution
        for label in labels:
            if label not in self.contributions["stats"]["class_distribution"]:
                self.contributions["stats"]["class_distribution"][label] = 0
            self.contributions["stats"]["class_distribution"][label] += 1
        
        # Track unique contributors
        unique_contributors = set()
        for c in self.contributions["contributions"]:
            unique_contributors.add(c["contributor_id"])
        self.contributions["stats"]["total_contributors"] = len(unique_contributors)
        
        self._save_contributions()
        return contribution["id"]
    
    def get_stats(self):
        return self.contributions["stats"]
    
    def get_all_contributions(self):
        return self.contributions["contributions"]


class DataManager:
    """Manage training data including images and labels."""
    
    def __init__(self):
        self.images_dir = os.path.join(DATA_FOLDER, "images")
        self.metadata_dir = os.path.join(DATA_FOLDER, "metadata")
        self.labels_file = os.path.join(self.metadata_dir, "labels.csv")
        self._ensure_labels_file()
    
    def _ensure_labels_file(self):
        if not os.path.exists(self.labels_file):
            pd.DataFrame(columns=["filename", "label", "contributor_id", "timestamp"]).to_csv(
                self.labels_file, index=False
            )
    
    def save_image(self, image_file, label, contributor_id):
        """Save an uploaded image and its label."""
        original_filename = secure_filename(image_file.filename)
        ext = original_filename.rsplit(".", 1)[-1].lower()
        unique_filename = f"{uuid.uuid4().hex}.{ext}"
        filepath = os.path.join(self.images_dir, unique_filename)
        
        # Validate and preprocess image
        try:
            img = Image.open(image_file)
            img = img.convert("RGB")
            img = img.resize((224, 224), Image.LANCZOS)
            img.save(filepath)
        except Exception as e:
            logger.error(f"Error processing image: {e}")
            raise ValueError(f"Invalid image file: {e}")
        
        # Append to labels CSV
        new_row = pd.DataFrame([{
            "filename": unique_filename,
            "label": label,
            "contributor_id": contributor_id,
            "timestamp": datetime.utcnow().isoformat()
        }])
        new_row.to_csv(self.labels_file, mode="a", header=False, index=False)
        
        return unique_filename
    
    def save_images_from_csv(self, csv_file, image_column, label_column, contributor_id):
        """Process a CSV file containing image paths/data and labels."""
        df = pd.read_csv(csv_file)
        
        if image_column not in df.columns or label_column not in df.columns:
            raise ValueError(f"CSV must contain columns '{image_column}' and '{label_column}'")
        
        saved_files = []
        labels = []
        
        for _, row in df.iterrows():
            image_data = row[image_column]
            label = str(row[label_column])
            
            # Handle base64 encoded images in CSV
            if isinstance(image_data, str) and len(image_data) > 260:
                try:
                    import base64
                    img_bytes = base64.b64decode(image_data)
                    img = Image.open(io.BytesIO(img_bytes))
                    img = img.convert("RGB")
                    img = img.resize((224, 224), Image.LANCZOS)
                    
                    unique_filename = f"{uuid.uuid4().hex}.png"
                    filepath = os.path.join(self.images_dir, unique_filename)
                    img.save(filepath)
                    
                    new_row = pd.DataFrame([{
                        "filename": unique_filename,
                        "label": label,
                        "contributor_id": contributor_id,
                        "timestamp": datetime.utcnow().isoformat()
                    }])
                    new_row.to_csv(self.labels_file, mode="a", header=False, index=False)
                    
                    saved_files.append(unique_filename)
                    labels.append(label)
                except Exception as e:
                    logger.warning(f"Could not process row: {e}")
                    continue
            # Handle file paths
            elif isinstance(image_data, str) and os.path.exists(image_data):
                try:
                    img = Image.open(image_data)
                    img = img.convert("RGB")
                    img = img.resize((224, 224), Image.LANCZOS)
                    
                    unique_filename = f"{uuid.uuid4().hex}.png"
                    filepath = os.path.join(self.images_dir, unique_filename)
                    img.save(filepath)
                    
                    new_row = pd.DataFrame([{
                        "filename": unique_filename,
                        "label": label,
                        "contributor_id": contributor_id,
                        "timestamp": datetime.utcnow().isoformat()
                    }])
                    new_row.to_csv(self.labels_file, mode="a", header=False, index=False)
                    
                    saved_files.append(unique_filename)
                    labels.append(label)
                except Exception as e:
                    logger.warning(f"Could not process image path {image_data}: {e}")
                    continue
        
        return saved_files, labels
    
    def load_dataset(self, img_size=(224, 224), validation_split=0.2):
        """Load all training data into numpy arrays."""
        if not os.path.exists(self.labels_file):
            raise ValueError("No training data available")
        
        df = pd.read_csv(self.labels_file)
        if len(df) == 0:
            raise ValueError("No training data available")
        
        images = []
        labels = []
        
        # Create label encoding
        unique_labels = sorted(df["label"].unique())
        label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
        
        for _, row in df.iterrows():
            filepath = os.path.join(self.images_dir, row["filename"])
            if os.path.exists(filepath):
                try:
                    img = Image.open(filepath).convert("RGB")
                    img = img.resize(img_size, Image.LANCZOS)
                    img_array = np.array(img) / 255.0
                    images.append(img_array)
                    labels.append(label_to_idx[row["label"]])
                except Exception as e:
                    logger.warning(f"Could not load image {filepath}: {e}")
        
        if len(images) == 0:
            raise ValueError("No valid images found in training data")
        
        images = np.array(images, dtype=np.float32)
        labels = np.array(labels, dtype=np.int32)
        
        # Shuffle
        indices = np.random.permutation(len(images))
        images = images[indices]
        labels = labels[indices]
        
        # Split
        split_idx = int(len(images) * (1 - validation_split))
        
        return {
            "train_images": images[:split_idx],
            "train_labels": labels[:split_idx],
            "val_images": images[split_idx:],
            "val_labels": labels[split_idx:],
            "class_names": unique_labels,
            "label_to_idx": label_to_idx,
            "num_classes": len(unique_labels)
        }
    
    def get_data_stats(self):
        """Get statistics about the current training data."""
        if not os.path.exists(self.labels_file):
            return {"total_samples": 0, "classes": [], "class_distribution": {}}
        
        df = pd.read_csv(self.labels_file)
        class_dist = df["label"].value_counts().to_dict()
        
        return {
            "total_samples": len(df),
            "classes": sorted(df["label"].unique().tolist()) if len(df) > 0 else [],
            "class_distribution": class_dist,
            "num_contributors": df["contributor_id"].nunique() if "contributor_id" in df.columns else 0
        }


class ModelBuilder:
    """Build and manage the image classification model."""
    
    def __init__(self, img_size=(224, 224, 3)):
        self.img_size = img_size
        self.model = None
        self.class_names = []
        self.model_path = os.path.join(MODEL_FOLDER, "latest_model")
        self.config_path = os.path.join(MODEL_FOLDER, "model_config.json")
    
    def build_model(self, num_classes, use_transfer_learning=True):
        """Build an image classification model."""
        if use_transfer_learning:
            # Use MobileNetV2 as base for efficiency
            base_model = keras.applications.MobileNetV2(
                input_shape=self.img_size,
                include_top=False,
                weights="imagenet"
            )
            base_model.trainable = False  # Freeze base model initially
            
            model = keras.Sequential([
                base_model,
                layers.GlobalAveragePooling2D(),
                layers.BatchNormalization(),
                layers.Dropout(0.3),
                layers.Dense(256, activation="relu"),
                layers.BatchNormalization(),
                layers.Dropout(0.3),
                layers.Dense(128, activation="relu"),
                layers.Dropout(0.2),
                layers.Dense(num_classes, activation="softmax")
            ])
        else:
            # Simple CNN for small datasets
            model = keras.Sequential([
                layers.Input(shape=self.img_size),
                layers.Conv2D(32, (3, 3), activation="relu", padding="same"),
                layers.BatchNormalization(),
                layers.MaxPooling2D((2, 2)),
                layers.Conv2D(64, (3, 3), activation="relu", padding="same"),
                layers.BatchNormalization(),
                layers.MaxPooling2D((2, 2)),
                layers.Conv2D(128, (3, 3), activation="relu", padding="same"),
                layers.BatchNormalization(),
                layers.MaxPooling2D((2, 2)),
                layers.Conv2D(256, (3, 3), activation="relu", padding="same"),
                layers.BatchNormalization(),
                layers.MaxPooling2D((2, 2)),
                layers.GlobalAveragePooling2D(),
                layers.Dense(256, activation="relu"),
                layers.Dropout(0.5),
                layers.Dense(128, activation="relu"),
                layers.Dropout(0.3),
                layers.Dense(num_classes, activation="softmax")
            ])
        
        model.compile(
            optimizer=keras.optimizers.Adam(learning_rate=0.001),
            loss="sparse_categorical_crossentropy",
            metrics=["accuracy"]
        )
        
        self.model = model
        return model
    
    def fine_tune(self, num_layers_to_unfreeze=20):
        """Unfreeze top layers of base model for fine-tuning."""
        if self.model and hasattr(self.model.layers[0], 'layers'):
            base_model = self.model.layers[0]
            base_model.trainable = True
            for layer in base_model.layers[:-num_layers_to_unfreeze]:
                layer.trainable = False
            
            self.model.compile(
                optimizer=keras.optimizers.Adam(learning_rate=0.0001),
                loss="sparse_categorical_crossentropy",
                metrics=["accuracy"]
            )
    
    def save_model(self, class_names):
        """Save model and configuration."""
        if self.model is None:
            raise ValueError("No model to save")
        
        self.model.save(self.model_path)
        
        config = {
            "class_names": class_names,
            "img_size": list(self.img_size),
            "saved_at": datetime.utcnow().isoformat(),
            "model_version": training_state.get("model_version", 0)
        }
        
        with open(self.config_path, "w") as f:
            json.dump(config, f, indent=2)
        
        logger.info(f"Model saved to {self.model_path}")
    
    def load_model(self):
        """Load a previously saved model."""
        if os.path.exists(self.model_path):
            self.model = keras.models.load_model(self.model_path)
            
            if os.path.exists(self.config_path):
                with open(self.config_path, "r") as f:
                    config = json.load(f)
                    self.class_names = config.get("class_names", [])
            
            logger.info("Model loaded successfully")
            return True
        return False
    
    def predict(self, image):
        """Make a prediction on a single image."""
        if self.model is None:
            if not self.load_model():
                raise ValueError("No trained model available")
        
        if isinstance(image, str):
            img = Image.open(image).convert("RGB")
        elif isinstance(image, Image.Image):
            img = image.convert("RGB")
        else:
            img = Image.open(io.BytesIO(image)).convert("RGB")
        
        img = img.resize((self.img_size[0], self.img_size[1]), Image.LANCZOS)
        img_array = np.array(img) / 255.0
        img_array = np.expand_dims(img_array, axis=0)
        
        predictions = self.model.predict(img_array, verbose=0)
        predicted_class_idx = np.argmax(predictions[0])
        confidence = float(predictions[0][predicted_class_idx])
        
        if not self.class_names and os.path.exists(self.config_path):
            with open(self.config_path, "r") as f:
                config = json.load(f)
                self.class_names = config.get("class_names", [])
        
        predicted_class = self.class_names[predicted_class_idx] if self.class_names else str(predicted_class_idx)
        
        all_predictions = {}
        for idx, prob in enumerate(predictions[0]):
            class_name = self.class_names[idx] if idx < len(self.class_names) else str(idx)
            all_predictions[class_name] = float(prob)
        
        return {
            "predicted_class": predicted_class,
            "confidence": confidence,
            "all_predictions": all_predictions
        }


class TrainingCallback(keras.callbacks.Callback):
    """Custom callback to update training state."""
    
    def on_epoch_end(self, epoch, logs=None):
        with state_lock:
            training_state["current_epoch"] = epoch + 1
            training_state["loss"] = float(logs.get("loss", 0))
            training_state["accuracy"] = float(logs.get("accuracy", 0))
            if "val_loss" in logs:
                training_state["val_loss"] = float(logs["val_loss"])
            if "val_accuracy" in logs:
                training_state["val_accuracy"] = float(logs["val_accuracy"])
        
        logger.info(
            f"Epoch {epoch + 1}: loss={logs.get('loss', 0):.4f}, "
            f"accuracy={logs.get('accuracy', 0):.4f}, "
            f"val_loss={logs.get('val_loss', 0):.4f}, "
            f"val_accuracy={logs.get('val_accuracy', 0):.4f}"
        )


# Initialize global objects
data_manager = DataManager()
model_builder = ModelBuilder()
contribution_tracker = ContributionTracker()

# Try to load existing model
model_builder.load_model()


def allowed_file(filename, allowed_extensions):
    return "." in filename and filename.rsplit(".", 1)[1].lower() in allowed_extensions


def run_training(epochs=50, batch_size=32, use_transfer_learning=True, fine_tune_epochs=20):
    """Run the training pipeline in a background thread."""
    global training_state
    
    try:
        with state_lock:
            training_state["is_training"] = True
            training_state["current_epoch"] = 0
        
        # Load dataset
        logger.info("Loading dataset...")
        dataset = data_manager.load_dataset()
        
        num_classes = dataset["num_classes"]
        class_names = dataset["class_names"]
        
        with state_lock:
            training_state["total_epochs"] = epochs + fine_tune_epochs
            training_state["total_samples"] = len(dataset["train_images"]) + len(dataset["val_images"])
            training_state["classes"] = class_names
        
        logger.info(f"Dataset loaded: {len(dataset['train_images'])} training, "
                     f"{len(dataset['val_images'])} validation samples, "
                     f"{num_classes} classes")
        
        # Data augmentation
        data_augmentation = keras.Sequential([
            layers.RandomFlip("horizontal"),
            layers.RandomRotation(0.2),
            layers.RandomZoom(0.2),
            layers.RandomContrast(0.2),
        ])
        
        # Create tf.data datasets for efficiency
        train_ds = tf.data.Dataset.from_tensor_slices(
            (dataset["train_images"], dataset["train_labels"])
        )
        train_ds = train_ds.shuffle(1000).batch(batch_size)
        train_ds = train_ds.map(
            lambda x, y: (data_augmentation(x, training=True), y),
            num_parallel_calls=tf.data.AUTOTUNE
        )
        train_ds = train_ds.prefetch(tf.data.AUTOTUNE)
        
        val_ds = tf.data.Dataset.from_tensor_slices(
            (dataset["val_images"], dataset["val_labels"])
        )
        val_ds = val_ds.batch(batch_size).prefetch(tf.data.AUTOTUNE)
        
        # Build model
        logger.info("Building model...")
        model = model_builder.build_model(
            num_classes=num_classes,
            use_transfer_learning=use_transfer_learning
        )
        
        model.summary(print_fn=logger.info)
        
        # Callbacks
        callbacks = [
            TrainingCallback(),
            keras.callbacks.EarlyStopping(
                monitor="val_loss",
                patience=10,
                restore_best_weights=True,
                verbose=1
            ),
            keras.callbacks.ReduceLROnPlateau(
                monitor="val_loss",
                factor=0.5,
                patience=5,
                min_lr=1e-7,
                verbose=1
            ),
            keras.callbacks.ModelCheckpoint(
                filepath=os.path.join(MODEL_FOLDER, "checkpoint_best"),
                monitor="val_accuracy",
                save_best_only=True,
                verbose=1
            )
        ]
        
        # Phase 1: Train with frozen base
        logger.info("Phase 1: Training with frozen base model...")
        model.fit(
            train_ds,
            validation_data=val_ds,
            epochs=epochs,
            callbacks=callbacks,
            verbose=1
        )
        
        # Phase 2: Fine-tuning
        if use_transfer_learning and fine_tune_epochs > 0:
            logger.info("Phase 2: Fine-tuning top layers...")
            model_builder.fine_tune(num_layers_to_unfreeze=20)
            
            with state_lock:
                training_state["total_epochs"] = epochs + fine_tune_epochs
            
            fine_tune_callbacks = [
                TrainingCallback(),
                keras.callbacks.EarlyStopping(
                    monitor="val_loss",
                    patience=5,
                    restore_best_weights=True,
                    verbose=1
                ),
                keras.callbacks.ReduceLROnPlateau(
                    monitor="val_loss",
                    factor=0.5,
                    patience=3,
                    min_lr=1e-8,
                    verbose=1
                )
            ]
            
            model.fit(
                train_ds,
                validation_data=val_ds,
                epochs=epochs + fine_tune_epochs,
                initial_epoch=epochs,
                callbacks=fine_tune_callbacks,
                verbose=1
            )
        
        # Evaluate
        logger.info("Evaluating model...")
        eval_results = model.evaluate(val_ds, verbose=0)
        logger.info(f"Final evaluation - Loss: {eval_results[0]:.4f}, Accuracy: {eval_results[1]:.4f}")
        
        # Save model
        model_builder.class_names = class_names
        model_builder.save_model(class_names)
        
        with state_lock:
            training_state["is_training"] = False
            training_state["last_trained"] = datetime.utcnow().isoformat()
            training_state["model_version"] += 1
            training_state["loss"] = float(eval_results[0])
            training_state["accuracy"] = float(eval_results[1])
        
        logger.info("Training completed successfully!")
        
    except Exception as e:
        logger.error(f"Training failed: {e}")
        with state_lock:
            training_state["is_training"] = False
            training_state["error"] = str(e)


