@app.route("/api/health", methods=["GET"])
def health_check():
    """Health check endpoint."""
    return jsonify({
        "status": "healthy",
        "timestamp": datetime.utcnow().isoformat(),
        "model_loaded": model_builder.model is not None
    })


@app.route("/api/upload/image", methods=["POST"])
def upload_image():
    """Upload a single image with its label for training."""
    if "image" not in request.files:
        return jsonify({"error": "No image file provided"}), 400
    
    image_file = request.files["image"]
    label = request.form.get("label")
    contributor_id = request.form.get("contributor_id", "anonymous")
    
    if not label:
        return jsonify({"error": "Label is required"}), 400
    
    if image_file.filename == "":
        return jsonify({"error": "No file selected"}), 400
    
    if not allowed_file(image_file.filename, ALLOWED_IMAGE_EXTENSIONS):
        return jsonify({"error": f"Invalid file type. Allowed: {ALLOWED_IMAGE_EXTENSIONS}"}), 400
    
    try:
        filename = data_manager.save_image(image_file, label, contributor_id)
        contribution_id = contribution_tracker.add_contribution(
            contributor_id, [filename], [label], source="single_upload"
        )
        
        return jsonify({
            "message": "Image uploaded successfully",
            "filename": filename,
            "label": label,
            "contribution_id": contribution_id,
            "contributor_id": contributor_id
        }), 201
    
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.error(f"Upload error: {e}")
        return jsonify({"error": "Internal server error"}), 500


@app.route("/api/upload/batch", methods=["POST"])
def upload_batch():
    """Upload multiple images with labels for training."""
    if "images" not in request.files:
        return jsonify({"error": "No image files provided"}), 400
    
    labels_json = request.form.get("labels")
    contributor_id = request.form.get("contributor_id", "anonymous")
    
    if not labels_json:
        return jsonify({"error": "Labels are required (JSON array)"}), 400
    
    try:
        labels = json.loads(labels_json)
    except json.JSONDecodeError:
        return jsonify({"error": "Invalid JSON for labels"}), 400
    
    image_files = request.files.getlist("images")
    
    if len(image_files) != len(labels):
        return jsonify({
            "error": f"Number of images ({len(image_files)}) must match number of labels ({len(labels)})"
        }), 400
    
    saved_files = []
    errors = []
    
    for idx, (image_file, label) in enumerate(zip(image_files, labels)):
        if not allowed_file(image_file.filename, ALLOWED_IMAGE_EXTENSIONS):
            errors.append(f"File {idx}: Invalid file type '{image_file.filename}'")
            continue
        
        try:
            filename = data_manager.save_image(image_file, label, contributor_id)
            saved_files.append({"filename": filename, "label": label})
        except Exception as e:
            errors.append(f"File {idx}: {str(e)}")
    
    if saved_files:
        filenames = [f["filename"] for f in saved_files]
        file_labels = [f["label"] for f in saved_files]
        contribution_id = contribution_tracker.add_contribution(
            contributor_id, filenames, file_labels, source="batch_upload"
        )
    else:
        contribution_id = None
    
    return jsonify({
        "message": f"Uploaded {len(saved_files)} of {len(image_files)} images",
        "uploaded": saved_files,
        "errors": errors,
        "contribution_id": contribution_id
    }), 201 if saved_files else 400


@app.route("/api/upload/csv", methods=["POST"])
def upload_csv():
    """Upload a CSV file containing image data and labels."""
    if "csv_file" not in request.files:
        return jsonify({"error": "No CSV file provided"}), 400
    
    csv_file = request.files["csv_file"]
    image_column = request.form.get("image_column", "image")
    label_column = request.form.get("label_column", "label")
    contributor_id = request.form.get("contributor_id", "anonymous")
    
    if not allowed_file(csv_file.filename, ALLOWED_CSV_EXTENSIONS):
        return jsonify({"error": "File must be a CSV"}), 400
    
    try:
        # Save CSV temporarily
        temp_path = os.path.join(UPLOAD_FOLDER, secure_filename(csv_file.filename))
        csv_file.save(temp_path)
        
        saved_files, labels = data_manager.save_images_from_csv(
            temp_path, image_column, label_column, contributor_id
        )
        
        # Clean up temp file
        os.remove(temp_path)
        
        if saved_files:
            contribution_id = contribution_tracker.add_contribution(
                contributor_id, saved_files, labels, source="csv_upload"
            )
        else:
            contribution_id = None
        
        return jsonify({
            "message": f"Processed {len(saved_files)} images from CSV",
            "num_images": len(saved_files),
            "contribution_id": contribution_id
        }), 201
    
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.error(f"CSV upload error: {e}")
        return jsonify({"error": f"Error processing CSV: {str(e)}"}), 500


@app.route("/api/upload/labeled-folder", methods=["POST"])
def upload_labeled_folder():
    """Upload images organized by label in a zip file."""
    if "zip_file" not in request.files:
        return jsonify({"error": "No zip file provided"}), 400
    
    import zipfile
    
    zip_file = request.files["zip_file"]
    contributor_id = request.form.get("contributor_id", "anonymous")
    
    try:
        temp_path = os.path.join(UPLOAD_FOLDER, secure_filename(zip_file.filename))
        zip_file.save(temp_path)
        
        saved_files = []
        saved_labels = []
        
        with zipfile.ZipFile(temp_path, "r") as z:
            for file_info in z.infolist():
                if file_info.is_dir():
                    continue
                
                parts = file_info.filename.split("/")
                if len(parts) < 2:
                    continue
                
                label = parts[-2]
                filename = parts[-1]
                
                ext = filename.rsplit(".", 1)[-1].lower() if "." in filename else ""
                if ext not in ALLOWED_IMAGE_EXTENSIONS:
                    continue
                
                try:
                    with z.open(file_info) as img_file:
                        img = Image.open(img_file).convert("RGB")
                        img = img.resize((224, 224), Image.LANCZOS)
                        
                        unique_filename = f"{uuid.uuid4().hex}.{ext}"
                        filepath = os.path.join(data_manager.images_dir, unique_filename)
                        img.save(filepath)
                        
                        new_row = pd.DataFrame([{
                            "filename": unique_filename,
                            "label": label,
                            "contributor_id": contributor_id,
                            "timestamp": datetime.utcnow().isoformat()
                        }])
                        new_row.to_csv(data_manager.labels_file, mode="a", header=False, index=False)
                        
                        saved_files.append(unique_filename)
                        saved_labels.append(label)
                except Exception as e:
                    logger.warning(f"Could not process {file_info.filename}: {e}")
        
        os.remove(temp_path)
        
        if saved_files:
            contribution_id = contribution_tracker.add_contribution(
                contributor_id, saved_files, saved_labels, source="zip_upload"
            )
        else:
            contribution_id = None
        
        return jsonify({
            "message": f"Extracted and saved {len(saved_files)} images",
            "num_images": len(saved_files),
            "labels_found": list(set(saved_labels)),
            "contribution_id": contribution_id
        }), 201
    
    except zipfile.BadZipFile:
        return jsonify({"error": "Invalid zip file"}), 400
    except Exception as e:
        logger.error(f"Zip upload error: {e}")
        return jsonify({"error": f"Error processing zip: {str(e)}"}), 500


@app.route("/api/train", methods=["POST"])
def start_training():
    """Start model training."""
    with state_lock:
        if training_state["is_training"]:
            return jsonify({"error": "Training is already in progress"}), 409
    
    # Parse training parameters
    params = request.get_json() or {}
    epochs = params.get("epochs", 50)
    batch_size = params.get("batch_size", 32)
    use_transfer_learning = params.get("use_transfer_learning", True)
    fine_tune_epochs = params.get("fine_tune_epochs", 20)
    
    # Validate we have enough data
    stats = data_manager.get_data_stats()
    if stats["total_samples"] < 10:
        return jsonify({
            "error": f"Not enough training data. Have {stats['total_samples']} samples, need at least 10."
        }), 400
    
    if len(stats["classes"]) < 2:
        return jsonify({
            "error": "Need at least 2 classes for classification."
        }), 400
    
    # Start training in background thread
    training_thread = threading.Thread(
        target=run_training,
        kwargs={
            "epochs": epochs,
            "batch_size": batch_size,
            "use_transfer_learning": use_transfer_learning,
            "fine_tune_epochs": fine_tune_epochs
        },
        daemon=True
    )
    training_thread.start()
    
    return jsonify({
        "message": "Training started",
        "parameters": {
            "epochs": epochs,
            "batch_size": batch_size,
            "use_transfer_learning": use_transfer_learning,
            "fine_tune_epochs": fine_tune_epochs
        },
        "data_stats": stats
    }), 202


