@app.route("/api/predict", methods=["POST"])
def predict():
    """Make a prediction on an uploaded image."""
    if "image" not in request.files:
        return jsonify({"error": "No image file provided"}), 400
    
    image_file = request.files["image"]
    
    if not allowed_file(image_file.filename, ALLOWED_IMAGE_EXTENSIONS):
        return jsonify({"error": f"Invalid file type. Allowed: {ALLOWED_IMAGE_EXTENSIONS}"}), 400
    
    try:
        result = model_builder.predict(image_file.read())
        return jsonify({
            "prediction": result,
            "model_version": training_state.get("model_version", 0)
        })
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.error(f"Prediction error: {e}")
        return jsonify({"error": f"Prediction failed: {str(e)}"}), 500


@app.route("/api/predict/feedback", methods=["POST"])
def prediction_feedback():
    """Submit feedback on a prediction to improve the model."""
    data = request.get_json()
    
    if not data:
        return jsonify({"error": "JSON body required"}), 400
    
    image_filename = data.get("image_filename")
    correct_label = data.get("correct_label")
    contributor_id = data.get("contributor_id", "anonymous")
    
    if not image_filename or not correct_label:
        return jsonify({"error": "image_filename and correct_label are required"}), 400
    
    # Check if image exists
    filepath = os.path.join(data_manager.images_dir, image_filename)
    if not os.path.exists(filepath):
        return jsonify({"error": "Image not found"}), 404
    
    # Add corrected label to training data
    new_row = pd.DataFrame([{
        "filename": image_filename,
        "label": correct_label,
        "contributor_id": contributor_id,
        "timestamp": datetime.utcnow().isoformat()
    }])
    new_row.to_csv(data_manager.labels_file, mode="a", header=False, index=False)
    
    contribution_tracker.add_contribution(
        contributor_id, [image_filename], [correct_label], source="feedback"
    )
    
    return jsonify({
        "message": "Feedback recorded. The model will improve on next training.",
        "image_filename": image_filename,
        "correct_label": correct_label
    }), 201


