@app.route("/api/contributions/leaderboard", methods=["GET"])
def contributions_leaderboard():
    """Get a leaderboard of top contributors."""
    contributions = contribution_tracker.get_all_contributions()
    
    contributor_counts = {}
    for c in contributions:
        cid = c["contributor_id"]
        if cid not in contributor_counts:
            contributor_counts[cid] = {"total_images": 0, "total_contributions": 0}
        contributor_counts[cid]["total_images"] += c["num_samples"]
        contributor_counts[cid]["total_contributions"] += 1
    
    leaderboard = [
        {"contributor_id": cid, **stats}
        for cid, stats in contributor_counts.items()
    ]
    leaderboard.sort(key=lambda x: x["total_images"], reverse=True)
    
    return jsonify({
        "leaderboard": leaderboard[:50]  # Top 50
    })


