@app.route("/api/data/validate", methods=["POST"])
def validate_contribution():
    """Validate or reject a community contribution (for moderators)."""
    data = request.get_json()
    
    if not data:
        return jsonify({"error": "JSON body required"}), 400
    
    contribution_id = data.get("contribution_id")
    is_valid = data.get("is_valid", True)
    moderator_id = data.get("moderator_id")
    
    if not contribution_id:
        return jsonify({"error": "contribution_id is required"}), 400
    
    contributions = contribution_tracker.get_all_contributions()
    
    for contrib in contributions:
        if contrib["id"] == contribution_id:
            contrib["validated"] = is_valid
            contrib["validated_by"] = moderator_id
            contrib["validated_at"] = datetime.utcnow().isoformat()
            
            # If rejected, remove the images from training data
            if not is_valid:
                df = pd.read_csv(data_manager.labels_file)
                df = df[~df["filename"].isin(contrib["filenames"])]
                df.to_csv(data_manager.labels_file, index=False)
                
                # Remove image files
                for filename in contrib["filenames"]:
                    filepath = os.path.join(data_manager.images_dir, filename)
                    if os.path.exists(filepath):
                        os.remove(filepath)
            
            contribution_tracker._save_contributions()
            
            return jsonify({
                "message": f"Contribution {'validated' if is_valid else 'rejected'}",
                "contribution_id": contribution_id
            })
    
    return jsonify({"error": "Contribution not found"}), 404


